  transform: scale(3);
}
.ol-overlay.zoomrotate {
  top: 50%;
  left: 50%;
  opacity:0.5;
  transform: translate(-50%,-50%) scale(0) rotate(360deg);
}
.ol-overlay.stretch {
  top: 50%;
  left: 50%;
  opacity:0.5;
  transform: translate(-50%,-50%) scaleX(0) ;
}
.ol-overlay.stretchy {
  top: 50%;
  left: 50%;
  opacity:0.5;
