.ol-timeline.ol-pointer .ol-center-date {
  display: block;
}
.ol-timeline.ol-pointer .ol-center-date:before, 
.ol-timeline.ol-pointer .ol-center-date:after {
  content: '';
  border: 0.3em solid transparent;
  border-width: .3em .25em;
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
}
