}
.ol-overlaycontainer .ol-touch-cursor .ol-button.ol-button-x:before {
  content: "\00D7";
  font-size: 1.2em;
  font-weight: bold;
}
.ol-overlaycontainer .ol-touch-cursor .ol-button.ol-button-move:before {
  content: "\2725";
  font-size: 1.2em;
}
.ol-overlaycontainer .ol-touch-cursor .ol-button.ol-button-check:before {
  content: "\2713";
