}

/** Placemark Needle/Pushpin */
.ol-popup.placemark.pushpin {	
  margin: -2.2em 0;
  transform: translate(0, -4em);
}
.ol-popup.placemark.pushpin > div {	
  border-radius: 0;
  background: transparent!important;
  box-shadow: inset 2em 0 currentColor;
  width: 1.1em;
